// src/components/ListingList.js
import ListingCard from "./ListingCard";

function ListingList() {
  const listings = [
    { title: "Cozy Apartment", location: "Mumbai", price: 150 },
    { title: "Luxury Villa", location: "Goa", price: 500 },
  ];

  const handleSelect = (listing) => {
    alert(`Selected: ${listing.title}`);
  };

  return (
    <div>
      {listings.map((listing, index) => (
        <ListingCard key={index} listing={listing} onSelect={handleSelect} />
      ))}
    </div>
  );
}

export default ListingList; // ✅ Default export
